+                           : qo_segment_offsets[batch_idx + 1] - qo_segment_offsets[batch_idx];
+      int kv_len = kv_lens ? kv_lens[batch_idx]
+                           : kv_segment_offsets[batch_idx + 1] - kv_segment_offsets[batch_idx];
